import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

ORIGINAL = {
  "19": {
    "1": "<p><strong>vayedaber YHWH el-Moshe ve'el-Aharon lemor</strong>: YHWH addresses both Moses and Aaron for the red heifer law — as in Numbers 18 (priestly duties), this law involves both prophetic and priestly leadership together. The joint address signals that what follows bridges civil and priestly jurisdiction.</p>",
    "2": "<p><strong>zot chukat hatorah</strong>: 'this is the statute of the Torah.' <em>Chukat</em> (statute/decree) designates a law whose rationale is not provided — it is obeyed because YHWH commands it, not because its logic is evident. The rabbis called the red heifer the archetypal <em>chok</em> (unexplained statute): it purifies the impure while rendering the pure impure. <strong>parah adumah</strong>: 'a red cow/heifer' — <em>parah</em> (cow) + <em>adumah</em> (red; from the root <em>adam</em>, same root as Adam, <em>adamah</em> earth, <em>dam</em> blood). The red color connects to blood and earth. <strong>asher lo-alah alehah ol</strong>: 'upon which a yoke has never come' — unblemished AND unworked; both requirements echo the sacrificial perfection standard.</p>",
    "3": "<p><strong>netatum otah el-Eleazar hakohen vehotzi otah el-michutz lamachaneh ushachat otah lefanav</strong>: 'give it to Eleazar the priest, and he shall take it outside the camp and slaughter it before him.' Two notable features: (1) The slaughter is done by Eleazar, not Aaron — the high priest is not directly involved, perhaps because the law involves corpse-impurity (which the high priest must strictly avoid, Lev 21:10-12). (2) <em>El-michutz lamachaneh</em>: outside the camp — a key spatial marker (cf. Lev 4:12, 21; Heb 13:11-13). Purity transactions happen outside the holy zone.</p>",
    "4": "<p><strong>velakach Eleazar hakohen midamah be'etzba'o vehizah el-nochach penei ohel-mo'ed midamah sheva pe'amim</strong>: 'Eleazar the priest shall take some of its blood with his finger and sprinkle some of its blood toward the front of the tent of meeting seven times.' The sevenfold blood-sprinkling toward the tabernacle — identical to the sin offering's blood-rite (Lev 4:6,17). The red heifer blood is not brought inside the tent but sprinkled toward it: a sin-offering motion performed for the whole community's ongoing purification.</p>",
    "5": "<p><strong>vesaraf et-haparah le'einav et-oroh ve'et-besarah ve'et-damah al-pirhah yisrof</strong>: 'the heifer shall be burned in his sight — its hide, its flesh, its blood, and its dung.' The entire animal is burned — no portion for the priest, no peace-offering meal, no altar burning; the whole heifer becomes ash. <em>Pirhah</em> (its dung) — even the contents of the intestines are burned; the completeness is absolute. The wholeness of the burning mirrors the olah (burnt offering) principle: total consumption, total transformation into ash.</p>",
    "6": "<p><strong>velakach hakohen etz erez ve'ezov usheni tola'at veheshtlich el-toch srefat haparah</strong>: 'the priest shall take cedarwood and hyssop and scarlet yarn, and throw them into the fire of the burning heifer.' The three materials — cedar, hyssop, scarlet — are the identical materials used in the purification of skin disease (Lev 14:4,6,49-51). The overlap signals that the red heifer purification addresses the same category of deep-seated impurity: death-like contamination requiring radical cleansing.</p>",
    "7": "<p><strong>vechibes begadav hakohen verachatz besaro bamayim ve'achar yavo el-hamachaneh vetame hakohen ad-ha'arev</strong>: 'the priest shall wash his clothes and bathe his body in water and afterward come into the camp. The priest shall be unclean until the evening.' The paradox appears: the priest who performs the purification rite becomes impure. He who cleanses others becomes unclean. <em>Tamei ad-ha'arev</em> (unclean until evening) — temporary but real. Hebrews 9:13-14 uses this paradox: 'If the blood of goats and bulls... sanctify for the purification of the flesh, how much more will the blood of Christ... purify our conscience from dead works?'</p>",
    "8": "<p><strong>vehasaref otah yechabes begadav bemayim verachatz besaro bamayim vetame ad-ha'arev</strong>: 'the one who burns it shall wash his clothes in water and bathe his body in water and be unclean until the evening.' The person who burns the heifer also becomes unclean — though the burning was the divinely commanded ritual act. Both the priest (blood-sprinkling) and the lay assistant (burning) are rendered impure by the purifying act. The paradox deepens: the instrument of purification is itself defiled by the contact with death-pollution it processes.</p>",
    "9": "<p><strong>ve'asaf ish tahor et efer haparah vehiniach michutz lamachaneh bemakom tahor vehayetah le'adat bnei-Yisrael lemishmeret lemei niddah chata'at hi</strong>: 'a man who is clean shall gather up the ashes of the heifer and deposit them outside the camp in a clean place. And they shall be kept for the water for impurity [<em>mei niddah</em>] for the congregation of Israel; it is a sin offering [<em>chata'at</em>].' The ashes are designated as both <em>mei niddah</em> (purification/impurity water — <em>niddah</em> means separation/impurity) and <em>chata'at</em> (sin offering). The heifer's ash is a standing sin offering held in reserve for community use — a permanent atoning resource deposited outside the camp.</p>",
    "10": "<p><strong>vechibes ha'osef et-efer haparah et-begadav vetame ad-ha'arev</strong>: 'the one who gathers the ashes of the heifer shall wash his clothes and be unclean until the evening.' The paradox is complete: even the gatherer of the purifying ashes becomes impure by the gathering. Four categories of people — the priest (v7), the burner (v8), the ash-gatherer (v10), and the sprinkler (v21) — all incur temporary uncleanness through handling the purifying material. The mechanism that purifies cannot be handled without cost.</p>",
    "11": "<p><strong>hanogea bemet lenefesh kol-adam yitma shivat yamim</strong>: 'whoever touches the dead body of any person shall be unclean seven days.' Corpse-impurity (<em>tum'at met</em>) — the most severe category of ritual impurity in the Levitical system — lasts seven days, requiring two applications of purification water (days 3 and 7). <em>Nefesh adam</em> (human soul/person) — the noun <em>nefesh</em> used for the corpse: the life (<em>nefesh</em>) has departed, leaving defilement.</p>",
    "12": "<p><strong>hu yitchata-bo bayom hashlishi uvayom hashvi'i yithar</strong>: 'he shall cleanse himself with it on the third day and on the seventh day, and so be clean.' The two-application structure — days 3 and 7 — may encode the death-to-resurrection pattern: day 3 (an intermediate purification, anticipating the day of resurrection; cf. the third-day pattern in OT typology) and day 7 (complete Sabbath-rest purity). If he does not cleanse himself on these specific days, the impurity persists.</p>",
    "13": "<p><strong>kol-hanogea bemet benefesh ha'adam asher yamut velo yitchata et-mishkan YHWH timeh</strong>: 'whoever touches a dead person, the body of anyone who has died, and does not cleanse himself, defiles the tabernacle of YHWH.' The severity: corpse-impurity that goes uncleansed defiles the central sanctuary. The impure individual's presence in the camp threatens the holy space at the center. <em>Ki mei niddah lo-zorak alav</em>: because the purification water was not sprinkled on him. The uncleansed is cut off (<em>nikretah ha-nefesh hahi miyisrael</em>).</p>",
    "14": "<p><strong>zot hatorah adam ki yamut be'ohel</strong>: 'this is the law: when a person dies in a tent.' The tent-death rule: everything in the tent and everyone who comes into the tent becomes unclean seven days. <em>Ohel</em> (tent) — the portable dwelling; in the wilderness context, all dwellings are tents. The tent that contains death spreads death-impurity to all it contains. This rule will later apply to houses in the land (Lev 14:33-45).</p>",
    "15": "<p><strong>vekhol keli patu'ach asher ein-tzamid pasil alav tameh hu</strong>: 'every open vessel with no cover fastened on it is unclean.' Open containers in a tent with a corpse absorb the impurity. Covered vessels are protected. The detail reflects the practical concern of preventing food and utensils from becoming defiled by proximity to death.</p>",
    "16": "<p><strong>vekhol asher yiga al-penei hasadeh bechalalei-cherev o bemet o be'etzem adam o bekever yitma shivat yamim</strong>: 'whoever in the open field touches one who has been killed with a sword or who has died naturally, or touches a human bone or a grave, shall be unclean seven days.' The corpse-impurity law extends to the open field: battlefield dead, natural deaths, bones, and graves all convey impurity. <em>Chalal cherev</em> (slain by sword) — battlefield deaths; <em>et etzem adam o kever</em> (human bone or grave). Even touching a grave conveys impurity — this is the background to Jesus's 'whitewashed tombs' accusation (Matt 23:27): Pharisees, who seek to appear righteous externally while internally spreading death, are like the graves that invisibly communicate impurity to those who unknowingly walk over them.</p>",
    "17": "<p><strong>velakhu latameh meavar hasreifah hachatat venatan alav mayim chayyim el-keli</strong>: 'for the unclean they shall take some of the ashes of the burned sin offering and add fresh water to them in a vessel.' <em>Avar hasreifah</em> (from the dust of the burning): the ash of the heifer combined with <em>mayim chayyim</em> (living/fresh water — flowing spring water, not stagnant) creates the purification solution. The paradox continues: inert ash + living water = purifying liquid.</p>",
    "18": "<p><strong>velakach ezov vetaval bamayim ish tahor vehizah al-ha'ohel ve'al kol-hakeilim ve'al hanefashot asher hayu sham</strong>: 'a clean person shall take hyssop and dip it in the water and sprinkle it on the tent and on all the furnishings and on the persons who were there.' <em>Ezov</em> (hyssop) — the sprinkling implement (cf. Exod 12:22 Passover; Ps 51:7: 'purify me with hyssop, and I shall be clean'). Hyssop appears at Passover, in skin disease purification, and here — consistently associated with blood-and-water cleansing. The hyssop reappears at the crucifixion (John 19:29).</p>",
    "19": "<p><strong>vehizah hatahor al-hatameh bayom hashlishi uvayom hashvi'i vechite'o vayom hashvi'i vecibes begadav verachatz bamayim vetaher ba'arev</strong>: 'the clean person shall sprinkle it on the unclean on the third day and on the seventh day. Thus on the seventh day he shall cleanse him, and he shall wash his clothes and bathe himself in water, and at evening he shall be clean.' The purification process: sprinkled day 3 and day 7; washed on day 7; clean at evening. The progression from impure to clean mirrors the creation-week structure, ending at the Sabbath moment (day 7 evening).</p>",
    "20": "<p><strong>ve'ish asher yitma velo yitchata venikretah ha-nefesh hahi mitkoch hakahal</strong>: 'but the man who is unclean and does not cleanse himself, that person shall be cut off from the midst of the assembly.' <em>Venikretah</em> (cut off/karet) — the covenant sanction for refusing purification. The one who refuses the provision for cleansing is cut off; the provision itself is not the problem, but refusing it is fatal. The red heifer's ash is the provision YHWH has made; ignoring it costs the covenant relationship.</p>",
    "21": "<p><strong>vetahayetah lahem lechukat olam umaze mei haniddah yechabes begadav vehanogea bemei haniddah yitma ad-ha'arev</strong>: 'and it shall be a statute forever for them. The one who sprinkles the water for impurity shall wash his clothes, and the one who touches the water for impurity shall be unclean until the evening.' Even the sprinkler incurs temporary impurity. The eternal statute (<em>chukat olam</em>) governs this: the mechanism that cleanses cannot itself be touched without cost. The paradox is permanent — built into creation-order.</p>",
    "22": "<p><strong>vekhol asher yiga bo hatameh yitma vehanefesh hanogaat tetama ad-ha'arev</strong>: 'whatever the unclean person touches shall be unclean, and whoever touches it shall be unclean until the evening.' The impurity transfer principle: the unclean communicates impurity by touch; the contamination extends through a single contact chain. This is why the red heifer law is necessary: without systematic purification, impurity could spread indefinitely through a community that regularly encounters death.</p>"
  },
  "20": {
    "1": "<p><strong>vayavo'u vnei-Yisrael kol-ha'edah midbar-Tzin bachodesh harishon vayeshev ha'am beKadesh vatamot sham Miriam vatikkaVer sham</strong>: 'the people of Israel came into the wilderness of Zin in the first month, and the people stayed in Kadesh. And Miriam died there and was buried there.' Miriam's death is reported in a single verse with no mourning record — in sharp contrast to Aaron's later death (vv28-29) and Moses's anticipated death (Deut 34). Miriam was the first of the three Exodus siblings to die, and Numbers places her death immediately before the water-crisis (vv2-13). <em>Kadesh</em> = holy/sacred; the place named for holiness is the site of both death and the sin at the waters.</p>",
    "2": "<p><strong>velo-hayah mayim la'edah vayikahalu al-Moshe ve'al-Aharon</strong>: 'and there was no water for the congregation. And they assembled themselves against Moses and against Aaron.' <em>Vayikahalu</em> (assembled against) — from <em>kahal</em> (assembly), but used here with the preposition <em>al</em> (against): the assembly forms itself in opposition. The same pattern as Korah's rebellion (16:3, 42). The repetition of wilderness murmuring at water-shortage (cf. Exod 17:1-7 at Rephidim/Massah-Meribah) signals a pattern of unbelief across the generation.</p>",
    "3": "<p><strong>vayarev ha'am im-Moshe vayomeru lemor</strong>: 'and the people quarreled with Moses and said.' <em>Vayarev</em> from <em>rib</em> (contend/quarrel) — the word that gives Meribah (<em>Merivah</em>) its name (v13). The people's specific lament: 'if only we had died when our brothers died before YHWH' — they prefer the deaths of Korah's rebellion as their own fate over the present thirst. An extraordinary statement of despair.</p>",
    "4": "<p><strong>velama heve'tem et-kehal YHWH el-hamidbar hazeh lamut sham anachnu uve'irenu</strong>: 'why have you brought the assembly of YHWH into this wilderness to die here, both we and our livestock?' <em>Kehal YHWH</em> (the assembly of YHWH) — the people identify themselves as YHWH's assembly even as they rebel. The complaint mirrors Exodus 17 almost word for word, showing the wilderness generation's cyclical unbelief despite the earlier Rephidim miracle.</p>",
    "5": "<p><strong>velama he'eletunu mimitzrayim lavi'enu el-hamakom hara hazeh</strong>: 'why have you made us come up out of Egypt to bring us to this evil place?' The rhetorical question that appears repeatedly in wilderness complaints: 'why Egypt?' The questioners define Egypt as good and the wilderness as evil — inverting the Exodus's entire theological framework. <em>Makom hara hazeh</em> (this evil place) — their evaluation of YHWH's chosen wilderness road.</p>",
    "6": "<p><strong>vayavo Moshe ve-Aharon miphney hakahal el-petach ohel-mo'ed vayiplu al-pneihem</strong>: 'Moses and Aaron went from the presence of the assembly to the entrance of the tent of meeting and fell on their faces.' The response to crisis: prostration before the tabernacle entrance. YHWH's glory (<em>kevod YHWH</em>) appears to them — as in the post-Korah plague intercession (17:10, Hebrew). The pattern: crisis → Moses/Aaron to the tent entrance → divine appearance.</p>",
    "7": "<p><strong>vayedaber YHWH el-Moshe lemor</strong>: YHWH speaks. The divine response to the water crisis is immediate. The instruction that follows is clear and specific — distinguishing this episode from Rephidim (Exod 17) where Moses was told to strike the rock.</p>",
    "8": "<p><strong>kach et-hamateh vehakel et-ha'edah atah ve-Aharon achicha vedibertem el-hassela le'eineihem venatan memaiv</strong>: 'take the staff, and assemble the congregation, you and Aaron your brother, and tell [<em>diber</em>] the rock before their eyes to yield its water.' Two commands: take the staff and <em>speak</em> to the rock (<em>daber</em>, not <em>naka</em> = strike). The rock of Rephidim had to be struck (Exod 17:6); this rock is to be addressed by word. The shift from striking to speaking reflects matured covenant communication — the word is sufficient.</p>",
    "9": "<p><strong>vayikach Moshe et-hamateh milifney YHWH ka'asher tzivahu</strong>: 'Moses took the staff from before YHWH, as he commanded him.' Moses obeys the first part of the command — he takes the staff. The staff (<em>matteh</em>) from before YHWH is likely Aaron's budding rod (17:10: 'put back the staff of Aaron before the testimony, to be kept as a sign'). Moses carries the staff of confirmed divine authority into the moment of crisis.</p>",
    "10": "<p><strong>vayakehilu Moshe ve-Aharon et-hakahal el-penei hassela vayomer lahem shim'u-na hamoriyim</strong>: 'Moses and Aaron gathered the assembly together before the rock, and he said to them: Hear now, you rebels.' <em>Hamoriyim</em> — 'rebels' (from <em>marah</em>, to rebel/be bitter). This is Moses addressing the people — but the anger is his, not YHWH's command. The tone has shifted from faithful intercession (v6: falling on his face) to confrontational accusation.</p>",
    "11": "<p><strong>vayarem Moshe et-yado vayak et-hassela bemattehu pa'amayim vayetze mayim rabbim vatesh ha'edah uve'ireyhem</strong>: 'Moses lifted up his hand and struck the rock with his staff twice, and water came out abundantly, and the congregation drank, and their livestock.' Moses strikes the rock — not once but twice. YHWH's command was to speak; Moses strikes. Water comes out abundantly (<em>mayim rabbim</em>) — the miracle occurs regardless of Moses's disobedience, but the sin has been committed. The abundance of water makes the disobedience more poignant: YHWH provides despite the failure of his servant.</p>",
    "12": "<p><strong>vayomer YHWH el-Moshe ve'el-Aharon yaan lo-he'emantem bi lehaqdisheni le'einei vnei Yisrael lachen lo tavi'u et-hakahal hazeh el-ha'aretz asher natati lahem</strong>: 'YHWH said to Moses and Aaron: Because you did not believe in me, to uphold me as holy in the eyes of the people of Israel, therefore you shall not bring this assembly into the land that I have given them.' The sentence is severe and its grounds are specific: <em>lo he'emantem bi</em> (you did not believe/trust in me) + <em>lehaqdisheni</em> (to sanctify me/make me holy before them). The sin was not merely procedural disobedience but a failure of trust and a failure to demonstrate YHWH's holiness. <em>He'emin</em> (believe/trust) — the same root as <em>amen</em>; <em>kadesh</em> (sanctify) — the same root as holiness/sanctuary. The two failures are theological, not merely ritual.</p>",
    "13": "<p><strong>hemah mei merivah asher-ravu vnei-Yisrael et-YHWH vayikadesh bam</strong>: 'these are the waters of Meribah, where the people of Israel quarreled with YHWH, and through them he showed himself holy.' <em>Mei Merivah</em> (waters of Meribah/quarreling): the place-name encodes Israel's sin. <em>Vayikadesh bam</em>: 'he showed himself holy through them' — despite and through the failure, YHWH's holiness was demonstrated. The holy name was not ultimately profaned; Moses's failure became the very occasion for YHWH's holiness to be visible.</p>",
    "14": "<p><strong>vayishlach Moshe mal'achim miKadesh el-melech Edom</strong>: 'Moses sent messengers from Kadesh to the king of Edom.' Edom is Israel's brother-nation — Esau's descendants. The message opens with <em>koh amar achyicha Yisrael</em> (thus says your brother Israel): covenant kinship is invoked. The request for passage through the <em>derech hamelech</em> (King's Highway) — the major north-south trade route east of the Jordan.</p>",
    "15": "<p><strong>veyede'u et asher asu-lanu mitzrayim</strong>: 'you know all the hardship that has come upon us, how our fathers went down to Egypt.' Moses's diplomatic speech invokes shared historical memory — the Egyptian sojourn affects both Israel and Edom as descendants of Jacob/Esau. The appeal is fraternal.</p>",
    "16": "<p><strong>vayishma YHWH bekoleinu vayishlach malach vayotzi'enu mimitzrayim</strong>: 'YHWH heard our voice and sent an angel and brought us out of Egypt.' The Exodus summary in diplomatic language: YHWH heard, sent an angel (<em>malach</em>), brought out. The <em>malach</em> of the Exodus is a recurring figure (Exod 14:19; 23:20; 33:2) whose identity is deeply debated — the Angel of YHWH who is identified with YHWH himself.</p>",
    "17": "<p><strong>na ne'evrah be'artzecha lo na'avor besadeh uvekerem velo nishteh mei be'er derech hamelech nelech lo nitteh yamin usmol</strong>: 'please let us pass through your land. We will not pass through field or vineyard, or drink water from a well. We will go along the King's Highway. We will not turn aside to the right hand or to the left.' <em>Derech hamelech</em> (King's Highway) — the major international route; Israel promises to stay on it, taking nothing. The diplomatic protocol is correct; the request is reasonable.</p>",
    "18": "<p><strong>vayomer elav Edom lo ta'avor bi pen-becharev etze likratecha</strong>: 'but Edom said to him: You shall not pass through, lest I come out with the sword against you.' Edom refuses. The fraternal appeal fails. The hostility between Israel and Edom — rooted in the Jacob/Esau rivalry (Gen 27) — persists through the wilderness period. The prophets (Obadiah; Isa 34; Amos 1:11) later pronounce judgment on Edom's persistent hostility to Jacob's descendants.</p>",
    "19": "<p><strong>vayomru elav bnei Yisrael bamesila na'aleh ve'im-memeiv nishteh ani uve'iruy venatati michram vrak ein-davar beragli e'evorah</strong>: Israel offers to pay for any water drunk and guarantees it is only a matter of passing through on foot. The repeated protest of harmless passage — <em>beragli e'evorah</em> (on foot I will pass through) — emphasizes Israel's peaceful intent.</p>",
    "20": "<p><strong>vayomer lo ta'avor vayetze Edom likrato be'am kaved uved-chazak</strong>: 'but he said: You shall not pass through. And Edom came out against them with a large army and with a strong force.' <em>Am kaved uved chazak</em> (heavy people and strong hand) — military terms. Israel turns aside. The road through Edom is blocked; Israel will have to go around, adding distance and hardship to the wilderness journey.</p>",
    "21": "<p><strong>vayema'en Edom netet et-Yisrael avor bigvulo vayyet Yisrael me'alav</strong>: 'Edom refused to give Israel passage through his territory, so Israel turned away from him.' <em>Vayma'en</em> (refused) — Edom's repeated refusal. Israel turns away (<em>vayyet</em>) — literally 'veered away.' The word anticipates the later wilderness journey narrative where veering away from YHWH's path is a constant temptation.</p>",
    "22": "<p><strong>vayisu miKadesh vayavo'u vnei Yisrael kol-ha'edah hor hahar</strong>: 'and they journeyed from Kadesh, and the people of Israel, the whole congregation, came to Mount Hor.' <em>Hor hahar</em> (Mount Hor) — a place name meaning literally 'the mountain of the mountain' or 'peak mountain,' location uncertain (traditionally identified with Jabal Harun near Petra). The next major event is Aaron's death.</p>",
    "23": "<p><strong>vayomer YHWH el-Moshe ve'el-Aharon behor hahar al-gevul eretz-Edom lemor</strong>: YHWH speaks at the Edom border. The connection between Edom's refusal and Aaron's death is temporal: the rejected passage and the dying of the old generation continue in sequence.</p>",
    "24": "<p><strong>ye'asef Aharon el-amav ki lo yavo el-ha'aretz asher natati livnei Yisrael yaan asher meritem et-pi lemei merivah</strong>: 'Aaron shall be gathered to his people, for he shall not enter the land that I have given to the people of Israel, because you rebelled against my command at the waters of Meribah.' <em>Ye'asef</em> (shall be gathered) — the <em>nif'al</em> passive: Aaron is gathered; his death is a being-taken. <em>El-amav</em> (to his people): the patriarchal death formula (cf. Gen 25:8 Abraham; 35:29 Isaac) — covenant belonging continues beyond death. The reason for Aaron's death outside the land is traced explicitly to <em>Merivah</em> (<em>asher meritem et-pi</em>: you rebelled against my mouth/command).</p>",
    "25": "<p><strong>kach et-Aharon ve'et-Eleazar beno veha'el otam hor hahar</strong>: 'take Aaron and Eleazar his son and bring them up to Mount Hor.' The three-generation ascent: Moses leads Aaron and Eleazar up the mountain. The father-son priestly succession is embedded in the death narrative.</p>",
    "26": "<p><strong>ufashat et-Aharon et-begadav vehalbashet otam et-Eleazar beno veAharon ye'asef umet sham</strong>: 'and strip Aaron of his garments and put them on Eleazar his son. And Aaron shall be gathered to his people and shall die there.' The transfer of the high-priestly garments from Aaron to Eleazar is the transfer of the priesthood itself. <em>Ufashat... vehalbashet</em> (strip... and put on): the investiture of Eleazar is simultaneously the divestiture of Aaron. The high-priestly office cannot die; it passes from father to son in the moment of death. Heb 7:23-24: the Levitical priests 'were prevented by death from continuing in office; but he [Christ] holds his priesthood permanently, because he continues forever.'</p>",
    "27": "<p><strong>vaya'as Moshe ka'asher tzivah YHWH vaya'alu el-hor hahar le'einei kol-ha'edah</strong>: 'Moses did as YHWH commanded. They went up to Mount Hor in the sight of all the congregation.' <em>Le'einei kol-ha'edah</em> (in the sight of all the congregation) — the succession is public, visible to the whole community. The priestly transition is not private or secret; the entire assembly witnesses Aaron's death and Eleazar's installation.</p>",
    "28": "<p><strong>vayifashet Moshe et-Aharon et-begadav vayalbes otam et-Eleazar beno vayamat Aharon sham bero'sh hahar</strong>: 'Moses stripped Aaron of his garments and put them on Eleazar his son. And Aaron died there on the top of the mountain.' Aaron dies clothed in the priestly absence of his garments — having given them to the next generation. The death of Aaron at the mountain top: naked of his office, yet within it. He dies as the priestly generation passes; the office lives in Eleazar.</p>",
    "29": "<p><strong>vayir'u kol-ha'edah ki gava Aharon vayivku et-Aharon shloshim yom kol beit Yisrael</strong>: 'when all the congregation saw that Aaron had breathed his last, all the house of Israel wept for Aaron thirty days.' <em>Gava</em> (breathed his last/expired) — the dying verb; <em>vayivku</em> (wept). Thirty days of mourning — the same as Moses will receive (Deut 34:8). The full-community mourning for Aaron stands in sharp contrast to the one-sentence burial of Miriam (v1). Aaron's death is communally mourned; he was the beloved high priest who stood between the living and the dead (16:48).</p>"
  },
  "21": {
    "1": "<p><strong>vayishma haKena'ani melech-Arad yoshev haNegev</strong>: 'when the Canaanite, the king of Arad, who lived in the Negev, heard.' The first military engagement after Aaron's death: Israel encounters Canaanite opposition from the south. Arad's king hears that Israel is coming by the 'way of Atharim' (perhaps the spies' route from Num 13). The proactive Canaanite attack — taking some prisoners — provokes Israel's vow.</p>",
    "2": "<p><strong>vayiddar Yisrael neder laYHWH vayomar im-naton titen et-ha'am hazeh beyadi vehacharamti et-areihem</strong>: 'and Israel vowed a vow to YHWH and said: If you will indeed give this people into my hand, then I will devote their cities to destruction [<em>cherem</em>].' <em>Vayiddar neder</em> (vowed a vow) — the cognate construction for emphasis. <em>Cherem</em> (irrevocable devotion/destruction) — total consecration to YHWH of the conquered cities; nothing kept for Israel. The vow conditions military success on YHWH's faithfulness and Israel's total renunciation of spoil. The site is named <em>Chormah</em> (destruction) after the fulfillment (v3).</p>",
    "3": "<p><strong>vayishma YHWH bekol Yisrael vayiten et-haKena'ani vayacharem otam ve'et-areihem vayikra shem-hamakom Chormah</strong>: 'YHWH heeded the voice of Israel and gave over the Canaanites, and they devoted them and their cities to destruction. So the name of the place was called Hormah.' <em>Vayishma YHWH bekol</em>: YHWH hears the voice of Israel — the prayer is heard. <em>Chormah</em> (from <em>cherem</em>): the place-name preserves the vow's fulfillment. This first land victory after a generation of failure anticipates the coming conquest.</p>",
    "4": "<p><strong>vayis'u meihor hahar derech Yam-Suf lisbot et-eretz Edom vatiketzer nefesh ha'am baderech</strong>: 'they journeyed from Mount Hor by the way to the Red Sea, to go around the land of Edom. And the people became impatient on the way.' <em>Vatiketzer nefesh ha'am</em>: literally 'the soul/spirit of the people became short' — <em>katzer</em> (short, cut short) applied to <em>nefesh</em> (soul/spirit/life). The idiom for impatience, frustration, discouragement: the spirit becomes 'too short' for the burden of the journey. The circuitous route around Edom shortens Israel's spiritual patience.</p>",
    "5": "<p><strong>vayedaber ha'am be'Elohim uveMoshe lamah he'elitunu mimitzrayim lamut bamidbar ki ein lechem ve'ein mayim venafshenu katzah balachem hakelokelt</strong>: 'the people spoke against God and against Moses: Why have you brought us up out of Egypt to die in the wilderness? For there is no food and no water, and we loathe this worthless food.' <em>Venapshenu katzah balachem hakelokelt</em>: 'our soul loathes/is disgusted with this contemptible food.' <em>Kelokelt</em> (contemptible/miserable/light) — a dismissive term for the manna. The people who once complained there was no food now despise the food YHWH provides. The escalation of complaint is notable: rejection of the gift itself.</p>",
    "6": "<p><strong>vayeshalach YHWH ba'am et hanechashim hasrafim vayyinashu et-ha'am vayamot am-rav miYisrael</strong>: 'YHWH sent fiery serpents among the people, and they bit the people, so that many people of Israel died.' <em>Nechashim srafim</em> (fiery/burning serpents): <em>saraf</em> means both 'burn' and is related to <em>seraphim</em> (the burning/fiery ones of Isa 6:2). The serpent sent as divine judgment on the manna-despising generation bites with fire. The connection to Eden's serpent is unmistakable: the original instrument of the fall returns as the instrument of covenant judgment.</p>",
    "7": "<p><strong>vayavo ha'am el-Moshe vayomru chatanu ki-dibarnu veYHWH uvach hitpalel el-YHWH veyasar me'alenu et-hanachash vayitpalel Moshe ba'ad ha'am</strong>: 'the people came to Moses and said: We have sinned, for we have spoken against YHWH and against you. Pray to YHWH, that he take away the serpents from us. So Moses prayed for the people.' <em>Chatanu</em> (we have sinned) — the sin is named. The pattern of judgment-confession-intercession-provision recurs from ch11 (Taberah, v1-3) and ch16 (Korah plague, 16:46-48). Moses's intercession is immediate and unrecorded — the prayer is brief; the provision is elaborate.</p>",
    "8": "<p>[Pre-existing entry — skipped by merge_comm]</p>",
    "9": "<p><strong>vaya'as Moshe nachash nechoshet vayesimehu al hanes vehayah im-nasach hanachash et-ish vehibit el-nachash hanechoshet vachai</strong>: 'Moses made a bronze serpent and set it on a pole. And if a serpent bit anyone, he would look at the bronze serpent and live.' The fulfillment of the look-and-live provision. <em>Al hanes</em> (on the pole/standard): the <em>nes</em> (pole/sign/banner/miracle) on which the serpent is raised is the same word used for military standards and miracles throughout Numbers. The image raised on the pole — which brings healing to those who look — becomes the explicit type Jesus names: 'As Moses lifted up the serpent in the wilderness, so must the Son of Man be lifted up, that whoever believes in him may have eternal life' (John 3:14-15).</p>",
    "10": "<p><strong>vayisu vnei Yisrael vayachanu be'Ovot</strong>: 'the people of Israel set out and camped at Oboth.' The journey resumes after the bronze serpent episode. The itinerary list (vv10-20) preserves the route through Transjordan with various stopping points. The names encode the wilderness experience: <em>Ovot</em> may connect to <em>ov</em> (spirit/ghost/necromancer) — the wilderness place-names often carry etymological memory.</p>",
    "11": "<p><strong>vayisu me'Ovot vayachanu be'Iye-ha'Avarim bamidbar asher al-penei Moav mimizrach hashemesh</strong>: 'they set out from Oboth and camped at Iye-abarim, in the wilderness that is opposite Moab, toward the sunrise.' <em>Iye-ha'Avarim</em> (ruins of the Abarim/crossings): the <em>Avarim</em> (those who cross over) are mentioned — this region borders the Jordan crossing territory. <em>Mimizrach hashemesh</em> (toward the sunrise) — the east/sunrise orientation marks progress toward Canaan.</p>",
    "12": "<p><strong>misham nas'u vayachanu benachal Zared</strong>: 'from there they set out and camped in the Valley of Zered.' <em>Nachal Zered</em> (Wadi Zered) — the traditional border between Edom/Moab territory; crossing the Zered marks a significant geographical transition in the wilderness journey (Deut 2:13-14 identifies crossing the Zered as the moment the military generation finished dying).</p>",
    "13": "<p><strong>misham nas'u vayachanu me'ever ha'Arnon asher bamidbar hayotze migvul ha'Emori ki Arnon gvul Moav bein Moav uvein ha'Emori</strong>: 'from there they set out and camped on the other side of the Arnon, which is in the wilderness that extends from the boundary of the Amorites. For the Arnon is the boundary of Moab, between Moab and the Amorites.' <em>Nachal Arnon</em> (the Arnon River/valley) — the border between Moab (south) and the Amorite kingdom of Sihon (north). The journey is now in the territory that Israel will need to traverse by defeating Sihon (vv21-32).</p>",
    "14": "<p><strong>al ken ye'amar besefer milchamot YHWH et-Vaheb beSufah venathalim Arnon</strong>: 'therefore it is said in the Book of the Wars of YHWH: Waheb in Suphah, and the valleys of the Arnon.' <em>Sefer milchamot YHWH</em> (Book of the Wars of YHWH) — an ancient Israelite source text now lost; cited here for the geographical/military record. The existence of this book suggests that Numbers draws on archival sources; it preserves a fragment of early Israelite military poetry.</p>",
    "15": "<p><strong>ve'eshed hanechalim asher natah leshevet Ar venishaan ligvul Moav</strong>: 'and the slope of the valleys that extends to the seat of Ar, and leans to the border of Moab.' The geographical detail of the journey route; the archival fragment continues with place-names along the Arnon valley.</p>",
    "16": "<p><strong>umiSham Be'erah hi habe'er asher amar YHWH leMoshe esof et-ha'am ve'etenah lahem mayim</strong>: 'and from there they continued to Beer; that is the well about which YHWH said to Moses: Gather the people together, so that I may give them water.' <em>Beer</em> = well. YHWH provides water again — this time without the Meribah failure; the provision is gracious, the response is poetic.</p>",
    "17": "<p><strong>az yashir Yisrael et-hashira hazot ali ve'er enu-lah</strong>: 'then Israel sang this song: Spring up, O well! — sing to it!' <em>Az yashir</em> (then sang) — the same introduction as the Song of the Sea (Exod 15:1). This brief well-song is Israel's second wilderness song. <em>Ali ve'er</em> (spring up, O well): the well is addressed directly as if it has agency. Paul later identifies the wilderness water-source as Christ: 'they drank from the spiritual Rock that followed them, and the Rock was Christ' (1 Cor 10:4).</p>",
    "18": "<p><strong>be'er charuha sarim kafruha nedivei ha'am bimechoqek bemish'anotam</strong>: 'a well that the princes dug, that the nobles of the people delved, with the scepter and with their staffs.' The leaders dig the well; the <em>mechoqeq</em> (scepter/lawgiver) and <em>mish'anot</em> (staffs) are used as digging tools. The imagery of rulers digging the well is unusual; it may encode the tradition of Moses striking the rock (now transformed into collaborative well-digging) or it may be a literal memory of a communally dug cistern.</p>",
    "19": "<p><strong>umiMidbar Matanah umiMatanah Nachaliel umiNachaliel Bamot</strong>: 'and from the wilderness to Mattanah, and from Mattanah to Nahaliel, and from Nahaliel to Bamoth.' The place-names are themselves theological: <em>Mattanah</em> = gift; <em>Nachaliel</em> = river/stream of God; <em>Bamot</em> = high places. The journey passes through places named Gift → River of God → High Places: a theological topography.</p>",
    "20": "<p><strong>umiVamot hagei asher bisadeh Moav rosh hapisgah venishkafah al-penei hayeshimon</strong>: 'and from Bamoth to the valley in the region of Moab by the top of Pisgah that overlooks the desert.' <em>Rosh hapisgah</em> (the top of Pisgah) — this peak will appear again in the Balaam oracles (Num 23:14) and as Moses's death location (Deut 34:1). The itinerary positions Israel at the height overlooking the Jordan valley — the land is visible from here.</p>",
    "21": "<p><strong>vayishlach Yisrael mal'achim el-Sichon melech ha'Emori lemor</strong>: Israel sends messengers to Sihon king of the Amorites. The diplomatic protocol mirrors the Edom request (20:14-21): the same language, the same King's Highway, the same promises. But Sihon is not a brother-nation — the Amorites have no covenantal claim against Israel's passage.</p>",
    "22": "<p><strong>e'evrah ve'artzecha lo nitteh besadeh uvecherem lo nishteh mei be'er derech hamelech nelech ad asher na'avor gvulecha</strong>: 'let me pass through your land. We will not turn aside into field or vineyard. We will not drink the water of a well. We will go by the King's Highway until we have passed through your territory.' The identical diplomatic formula used with Edom — word for word. The comparison is deliberate: Israel makes the same request, but Edom (a brother) and Sihon (an Amorite) both refuse. The Amorite refusal, unlike Edom's, leads to war.</p>",
    "23": "<p><strong>velo-natan Sichon et-Yisrael avor bigvulo vaye'esof Sichon et-kol-ammo vayetze likrat Yisrael hamilbarah</strong>: 'but Sihon did not allow Israel to pass through his territory. He gathered all his people together and went out against Israel to the wilderness.' <em>Hamilbarah</em> (to the wilderness/desert) — Sihon comes out to attack in the open desert terrain. Deuteronomy 2:30 adds: 'YHWH your God hardened his spirit and made his heart obstinate, that he might give him into your hand.' Sihon's refusal is the divinely-ordained trigger for Israel's first major land victory.</p>",
    "24": "<p><strong>vayakkehu Yisrael lefi-charev vayirash et-artzo miArnon ad-Yabok</strong>: 'Israel struck him with the edge of the sword and took possession of his land from the Arnon to the Jabbok.' <em>Lefi-charev</em> (at the mouth of the sword) — the sword's edge expressed as its mouth (<em>peh</em>, the same word as mouth for speech and water-giving). <em>Vayirash</em> (took possession) — the verb of covenant inheritance: Israel takes possession (<em>yarash</em>) of the first Transjordanian territory. The Arnon to Jabbok boundary becomes Israelite territory.</p>",
    "25": "<p><strong>vayikach Yisrael et kol-he'arim ha'eleh vayeshev Yisrael bekol-arei ha'Emori beCheshbon uvechal-banotehah</strong>: 'Israel took all these cities, and Israel settled in all the cities of the Amorites, in Heshbon, and in all its villages.' <em>Vayeshev</em> (settled/dwelt) — Israel inhabits the Amorite cities. This is the first settlement in territory east of the Jordan — the beginning of the conquest pattern.</p>",
    "26": "<p><strong>ki Cheshbon ir Sichon melech ha'Emori hi vehu nilcham bemelech Moav harishon vayikach et-kol-artzo miyado ad-Arnon</strong>: 'for Heshbon was the city of Sihon the king of the Amorites, who had fought against the former king of Moab and taken all his land from him as far as the Arnon.' Historical context: Heshbon had been Moabite before Sihon conquered it. Israel conquers what was Moab's former territory through Sihon — an indirect inheritance through conquest.</p>",
    "27": "<p><strong>al-ken yomru hamoshlim bo'u Cheshbon tibbaneh vetikonen ir Sichon</strong>: 'therefore the ballad singers say: Come to Heshbon, let it be built; let the city of Sihon be established.' A poetic fragment from the <em>moshlim</em> (those who compose proverbs/songs) celebrating Sihon's former victory — which Israel now inherits. The taunt song against Moab (vv27-30) was originally a celebration of Sihon's conquest of Moab; Israel now sings it as their own victory song, having defeated Sihon.</p>",
    "28": "<p><strong>ki esh yatze'ah miCheshbon lehabah mir'kiryat Sichon achlah Ar Moav ba'alei bamot Arnon</strong>: 'for fire came out from Heshbon, flame from the city of Sihon. It devoured Ar of Moab, and swallowed the heights of the Arnon.' The taunt poem: fire/flame imagery for military conquest. <em>Esh... lehabah</em> (fire... flame) — two terms for the unstoppable advance. Moab's destruction by Sihon (now inherited by Israel's victory) is described in fire-language that resonates with the divine fire motif throughout Numbers.</p>",
    "29": "<p><strong>oy-lecha Moav avadeta am Kemosh natan banav pelitim uvenotav bashevut lemelech Emori Sichon</strong>: 'woe to you, O Moab! You are undone, O people of Chemosh! He has made his sons fugitives, and his daughters captives, to an Amorite king, Sihon.' <em>Chemosh</em> — Moab's national deity. The taunt names Chemosh as the failed divine protector: 'his sons became fugitives... to an Amorite king.' YHWH defeats the nations by defeating their gods. <em>Oy-lecha</em> (woe to you) — the prophetic woe oracle applied in taunt poetry.</p>",
    "30": "<p><strong>vanniram avad Cheshbon ad-Divon vanavashim ad-Nofa asher ad-Medeivah</strong>: 'we overthrew them; Heshbon, as far as Dibon, perished; and we laid waste as far as Nophah, which reaches to Medeba.' The conclusion of the taunt song. The place names — Dibon, Nophah, Medeba — mark Moabite territory now claimed by Israel's advance. The song ends with comprehensive destruction.</p>",
    "31": "<p><strong>vayeshev Yisrael be'eretz ha'Emori</strong>: 'Israel settled in the land of the Amorites.' The settlement verb (<em>vayeshev</em>) repeats from v25: the conquest becomes habitation. The land east of the Jordan is now Israelite territory, claimed by victory over Sihon.</p>",
    "32": "<p><strong>vayishlach Moshe laragel et-Yazer vayilkedu et-benotehah vayorish et-ha'Emori asher-sham</strong>: 'Moses sent to spy out Jazer, and they captured its villages and dispossessed the Amorites who were there.' <em>Laragel</em> (to spy out) — a small reconnaisance that contrasts with the catastrophic spying of Numbers 13; this time, the spying leads immediately to capture, not despair.</p>",
    "33": "<p><strong>vayifnu vaya'alu derech haBashan vayetze Og melech haBashan likratam hu vekhol-ammo lamilchamah beEdre'i</strong>: 'they turned and went up by the way of Bashan. And Og the king of Bashan came out against them, he and all his people, to battle at Edrei.' Og of Bashan — the giant king (Deut 3:11: his iron bed was 9 cubits long) whose kingdom extends north of Gilead. His coming out against Israel repeats Sihon's pattern.</p>",
    "34": "<p><strong>vayomer YHWH el-Moshe al-tira oto ki veyad'cha natattihu ve'et-kol-ammo ve'et-artzo</strong>: 'YHWH said to Moses: Do not fear him, for I have given him into your hand, and all his people, and his land.' <em>Al-tira</em> (do not fear) — the divine assurance before battle. YHWH's word precedes the victory: the outcome is given before the fight. The same formula recurs throughout Joshua (1:9; 10:8) and becomes the foundation for Israel's conquest confidence.</p>",
    "35": "<p><strong>vayakku oto vet-banav vekhol-ammo ad-bilti hish'ir-lo sarid vayirshu et-artzo</strong>: 'and they struck him and his sons and all his people, until he had no survivor left. And they possessed his land.' <em>Ad-bilti hish'ir-lo sarid</em>: 'until no survivor remained' — the totality of the <em>cherem</em>-pattern victory. <em>Vayirshu</em> (they possessed) — the same possession-verb as v24. The double conquest of Sihon and Og east of the Jordan establishes the Transjordanian foothold from which Joshua will launch the main Canaan campaign. Moses's sermon in Deuteronomy returns to these two victories as the paradigm for Israel's faith in YHWH's conquest promises.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'numbers')
    merge_comm(c, ORIGINAL)
    save_comm('mkt-original', 'numbers', c)
    print('Numbers 19-21 mkt-original written.')

if __name__ == '__main__':
    main()
